import org.eclipse.rdf4j.model.vocabulary.RDF;
import org.junit.jupiter.api.Test;

class SparseWholeBgpSketchAccuracyTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final String SCHEMA = "https://schema.org/";
	private static final IRI PERSON = schema("Person");
	private static final IRI MEMBER_OF = schema("memberOf");
	private static final IRI DEPARTMENT = schema("department");
	private static final IRI MAKES_OFFER = schema("makesOffer");
	private static final IRI ITEM_OFFERED = schema("itemOffered");
	private static final IRI ABOUT = schema("about");
	private static final IRI MAIN_ENTITY_OF_PAGE = schema("mainEntityOfPage");
	private static final IRI REVIEW = schema("review");
	private static final IRI REVIEW_RATING = schema("reviewRating");
	private static final IRI RATING_VALUE = schema("ratingValue");

	private static final int TUPLE_EXACT_K = 16_384;
	private static final int TUPLE_REPORT_K = 64;
	private static final int SKETCH_ROWS = 5;
	private static final int SKETCH_BUCKETS = 1_024;
	private static final long SKETCH_SEED = 0x51E7C0DEL;

	@Test
	void sparseWholeBgpLogsEstimatorAccuracy() {
		Model model = ThemeDataSetGenerator.generate(Theme.SPARSE);
		WholeBgpStats stats = exactWholeBgpStats(model);
		FragmentSketches left = sketchesFor(stats.leftCounts());
		FragmentSketches right = sketchesFor(stats.rightCounts());

		double tupleExactEstimate = TupleSketchOps.estimateIntersectionProductSum(left.exactTupleSketch(),
				right.exactTupleSketch(), TUPLE_EXACT_K);
		double tupleProductEstimate = TupleSketchOps.estimateIntersectionProductSum(left.reportTupleSketch(),
				right.reportTupleSketch(), TUPLE_REPORT_K);
		double fastAgmsEstimate = left.fastAgms()
				.innerProduct(right.fastAgms());
		double joinSketchEstimate = left.joinSketch()
				.innerProduct(right.joinSketch());
		double omniSketchEstimate = left.omniSketch()
				.innerProduct(right.omniSketch());

		logDistinctOnlyGuard(stats);
		logEstimate("exact", stats.exactRows(), stats);
		logEstimate("tupleExactEstimate", tupleExactEstimate, stats);
		logEstimate("tupleSketchProduct", tupleProductEstimate, stats);
		logEstimate("fastAgms", fastAgmsEstimate, stats);
		logEstimate("joinSketch", joinSketchEstimate, stats);
		logEstimate("omniSketch", omniSketchEstimate, stats);

		assertAll(
				() -> assertEquals(480_000L, stats.leftRows()),
				() -> assertEquals(120_000L, stats.rightRows()),
				() -> assertEquals(8_000, stats.leftDistinctWorks()),
				() -> assertEquals(400, stats.rightDistinctWorks()),
				() -> assertEquals(400, stats.intersectionWorks()),
				() -> assertEquals(7_200_000L, stats.exactRows()),
				() -> assertTrue(stats.exactRows() > stats.intersectionWorks(),
						"distinct work intersection is not the duplicate-aware join cardinality"),
				() -> assertEquals(7_200_000.0d, tupleExactEstimate, 0.0d,
						"high-enough tuple sketch must preserve duplicate-aware product sums"),
				() -> assertValidEstimate("tupleSketchProduct", tupleProductEstimate),
				() -> assertValidEstimate("fastAgms", fastAgmsEstimate),
				() -> assertValidEstimate("joinSketch", joinSketchEstimate),
				() -> assertValidEstimate("omniSketch", omniSketchEstimate));
	}

	private static WholeBgpStats exactWholeBgpStats(Model model) {
		SparseIndexes indexes = indexesFor(model);
		Map<Value, Long> leftCounts = leftCountsByWork(indexes);
		Map<Value, Long> rightCounts = rightCountsByWork(indexes);
		long leftRows = sum(leftCounts);
		long rightRows = sum(rightCounts);
		long exactRows = exactInnerProduct(leftCounts, rightCounts);
		long intersectionWorks = intersectionSize(leftCounts.keySet(), rightCounts.keySet());
		return new WholeBgpStats(leftCounts, rightCounts, leftRows, rightRows, exactRows, intersectionWorks);
	}

	private static SparseIndexes indexesFor(Model model) {
		Set<Value> people = new HashSet<>();
		for (Statement statement : model) {
			if (statement.getPredicate().equals(RDF.TYPE) && statement.getObject().equals(PERSON)) {
				people.add(statement.getSubject());
			}
		}

		Map<Value, Long> peopleByOrg = new HashMap<>();
		Map<Value, Set<Value>> departmentsByOrg = new HashMap<>();
		Map<Value, Set<Value>> offersByDepartment = new HashMap<>();
		Map<Value, Value> workByOffer = new HashMap<>();
		Map<Value, Value> topicByWork = new HashMap<>();
		Set<Value> topicsWithPage = new HashSet<>();
		Map<Value, Set<Value>> reviewsByWork = new HashMap<>();
		Map<Value, Value> ratingByReview = new HashMap<>();
		Set<Value> ratingsWithValue = new HashSet<>();

		for (Statement statement : model) {
			IRI predicate = statement.getPredicate();
			Value subject = statement.getSubject();
			Value object = statement.getObject();
			if (predicate.equals(MEMBER_OF) && people.contains(subject)) {
				peopleByOrg.merge(object, 1L, Long::sum);
			} else if (predicate.equals(DEPARTMENT)) {
				add(departmentsByOrg, subject, object);
			} else if (predicate.equals(MAKES_OFFER)) {
				add(offersByDepartment, subject, object);
			} else if (predicate.equals(ITEM_OFFERED)) {
				workByOffer.put(subject, object);
			} else if (predicate.equals(ABOUT)) {
				topicByWork.put(subject, object);
			} else if (predicate.equals(MAIN_ENTITY_OF_PAGE)) {
				topicsWithPage.add(subject);
			} else if (predicate.equals(REVIEW)) {
				add(reviewsByWork, subject, object);
			} else if (predicate.equals(REVIEW_RATING)) {
				ratingByReview.put(subject, object);
			} else if (predicate.equals(RATING_VALUE)) {
				ratingsWithValue.add(subject);
			}
		}

		return new SparseIndexes(peopleByOrg, departmentsByOrg, offersByDepartment, workByOffer, topicByWork,
				topicsWithPage, reviewsByWork, ratingByReview, ratingsWithValue);
	}

	private static Map<Value, Long> leftCountsByWork(SparseIndexes indexes) {
		Map<Value, Long> counts = new HashMap<>();
		for (Map.Entry<Value, Long> orgEntry : indexes.peopleByOrg()
				.entrySet()) {
			long peopleInOrg = orgEntry.getValue();
			for (Value department : indexes.departmentsByOrg()
					.getOrDefault(orgEntry.getKey(), Set.of())) {
				for (Value offer : indexes.offersByDepartment()
						.getOrDefault(department, Set.of())) {
					Value work = indexes.workByOffer()
							.get(offer);
					if (work == null) {
						continue;
					}
					Value topic = indexes.topicByWork()
							.get(work);
					if (topic != null && indexes.topicsWithPage()
							.contains(topic)) {
						counts.merge(work, peopleInOrg, Long::sum);
					}
				}
			}
		}
		return counts;
	}

	private static Map<Value, Long> rightCountsByWork(SparseIndexes indexes) {
		Map<Value, Long> counts = new HashMap<>();
		for (Map.Entry<Value, Set<Value>> entry : indexes.reviewsByWork()
				.entrySet()) {
			long rows = 0L;
			for (Value review : entry.getValue()) {
				Value rating = indexes.ratingByReview()
						.get(review);
				if (rating != null && indexes.ratingsWithValue()
						.contains(rating)) {
					rows++;
				}
			}
			if (rows > 0L) {
				counts.put(entry.getKey(), rows);
			}
		}
		return counts;
	}

	private static FragmentSketches sketchesFor(Map<Value, Long> counts) {
		ArrayOfDoublesUpdatableSketch exactTupleSketch = TupleSketchOps.newSketch(TUPLE_EXACT_K);
		ArrayOfDoublesUpdatableSketch reportTupleSketch = TupleSketchOps.newSketch(TUPLE_REPORT_K);
		FastAgmsFrequencySketch fastAgms = new FastAgmsFrequencySketch(SKETCH_ROWS, SKETCH_BUCKETS, SKETCH_SEED);
		JoinFrequencySketch joinSketch = new JoinFrequencySketch(SKETCH_ROWS, SKETCH_BUCKETS, 256, 256, 64L,
				SKETCH_SEED);
		OmniFrequencySketch omniSketch = new OmniFrequencySketch(SKETCH_ROWS, SKETCH_BUCKETS, 512, SKETCH_SEED);
		for (Map.Entry<Value, Long> entry : counts.entrySet()) {
			long key = stableHash(entry.getKey()
					.stringValue());
			long count = entry.getValue();
			TupleSketchOps.update(exactTupleSketch, key, count);
			TupleSketchOps.update(reportTupleSketch, key, count);
			fastAgms.update(key, count);
			joinSketch.update(key, count);
			omniSketch.update(key, count);
		}
		return new FragmentSketches(exactTupleSketch, reportTupleSketch, fastAgms, joinSketch, omniSketch);
	}

	private static long exactInnerProduct(Map<Value, Long> left, Map<Value, Long> right) {
		Map<Value, Long> smaller = left.size() <= right.size() ? left : right;
		Map<Value, Long> larger = smaller == left ? right : left;
		long rows = 0L;
		for (Map.Entry<Value, Long> entry : smaller.entrySet()) {
			rows += entry.getValue() * larger.getOrDefault(entry.getKey(), 0L);
		}
		return rows;
	}

	private static long intersectionSize(Set<Value> left, Set<Value> right) {
		Set<Value> smaller = left.size() <= right.size() ? left : right;
		Set<Value> larger = smaller == left ? right : left;
		long count = 0L;
		for (Value value : smaller) {
			if (larger.contains(value)) {
				count++;
			}
		}
		return count;
	}

	private static long sum(Map<Value, Long> counts) {
		long rows = 0L;
		for (long count : counts.values()) {
			rows += count;
		}
		return rows;
	}

	private static void add(Map<Value, Set<Value>> index, Value key, Value value) {
		index.computeIfAbsent(key, ignored -> new HashSet<>())
				.add(value);
	}

	private static void assertValidEstimate(String estimator, double estimate) {
		assertTrue(Double.isFinite(estimate), estimator + " estimate must be finite: " + estimate);
		assertTrue(estimate >= 0.0d, estimator + " estimate must be non-negative: " + estimate);
	}

	private static void logDistinctOnlyGuard(WholeBgpStats stats) {
		System.out.printf(Locale.ROOT,
				"sparseWholeBgp distinctOnlyIntersectionWorks=%d duplicateAwareExactRows=%d leftRows=%d rightRows=%d "
						+ "leftDistinctWorks=%d rightDistinctWorks=%d%n",
				stats.intersectionWorks(), stats.exactRows(), stats.leftRows(), stats.rightRows(),
				stats.leftDistinctWorks(), stats.rightDistinctWorks());
	}

	private static void logEstimate(String estimator, double estimate, WholeBgpStats stats) {
		double absoluteError = Math.abs(estimate - stats.exactRows());
		double relativeError = absoluteError / Math.max(1.0d, stats.exactRows());
		System.out.printf(Locale.ROOT,
				"sparseWholeBgp estimator=%s estimate=%.3f exact=%d absError=%.3f relativeError=%.6f qError=%.6f "
						+ "leftRows=%d rightRows=%d leftDistinctWorks=%d rightDistinctWorks=%d intersectionWorks=%d%n",
				estimator, estimate, stats.exactRows(), absoluteError, relativeError,
				qError(estimate, stats.exactRows()), stats.leftRows(), stats.rightRows(), stats.leftDistinctWorks(),
				stats.rightDistinctWorks(), stats.intersectionWorks());
	}

	private static double qError(double estimate, long exact) {
		double estimated = Math.max(1.0d, estimate);
		double truth = Math.max(1.0d, exact);
		return Math.max(estimated / truth, truth / estimated);
	}

	private static long stableHash(String value) {
		long hash = 0xcbf29ce484222325L;
		for (int i = 0; i < value.length(); i++) {
			hash ^= value.charAt(i);
			hash *= 0x100000001b3L;
		}
		return hash == Long.MIN_VALUE ? 0L : hash;
	}

	private static IRI schema(String localName) {
		return VF.createIRI(SCHEMA + localName);
	}

	private record SparseIndexes(
			Map<Value, Long> peopleByOrg,
			Map<Value, Set<Value>> departmentsByOrg,
			Map<Value, Set<Value>> offersByDepartment,
			Map<Value, Value> workByOffer,
			Map<Value, Value> topicByWork,
			Set<Value> topicsWithPage,
			Map<Value, Set<Value>> reviewsByWork,
			Map<Value, Value> ratingByReview,
			Set<Value> ratingsWithValue) {
	}

	private record WholeBgpStats(
			Map<Value, Long> leftCounts,
			Map<Value, Long> rightCounts,
			long leftRows,
			long rightRows,
			long exactRows,
			long intersectionWorks) {

		int leftDistinctWorks() {
			return leftCounts.size();
		}

		int rightDistinctWorks() {
			return rightCounts.size();
		}
	}

	private record FragmentSketches(
			ArrayOfDoublesUpdatableSketch exactTupleSketch,
			ArrayOfDoublesUpdatableSketch reportTupleSketch,
			FastAgmsFrequencySketch fastAgms,
			JoinFrequencySketch joinSketch,
			OmniFrequencySketch omniSketch) {
	}
}
